using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Breaking change 1: EF Core 9 renames the discriminator JSON
            // property from "Discriminator" to "$type". Existing 500K documents
            // and direct SQL queries (c.Discriminator) rely on the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF Core 9 stores the id as just the key
            // value (e.g. "123") instead of "Product|123". Existing documents
            // use the old format, so reads/finds would fail without this.
            entity.Property("__id")
                .HasValueGeneratorFactory<LegacyCosmosIdGeneratorFactory>();

            // Breaking change 3: HasIndex is ignored by the Cosmos provider
            // and throws InvalidOperationException in EF Core 9.
            // Removed: entity.HasIndex(p => p.Sku);
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = null!;
}

/// <summary>
/// Reproduces the EF Core 8 Cosmos id format: "{Discriminator}|{Key}"
/// so that existing documents written by EF Core 8 remain accessible.
/// </summary>
internal sealed class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue()?.ToString()
                            ?? entry.Metadata.ShortName();
        var key = entry.Property(
            entry.Metadata.FindPrimaryKey()!.Properties[0].Name).CurrentValue;
        return $"{discriminator}|{key}";
    }
}

internal sealed class LegacyCosmosIdGeneratorFactory : ValueGeneratorFactory
{
    public override ValueGenerator Create(
        Microsoft.EntityFrameworkCore.Metadata.IProperty property,
        Microsoft.EntityFrameworkCore.Metadata.ITypeBase typeBase)
        => new LegacyCosmosIdGenerator();
}

