using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // Breaking change 4: The Cosmos provider removed synchronous I/O
    // in EF Core 9.  All queries must use async APIs.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL – works because we preserved "Discriminator"
        // as the JSON property name (see ProductContext.HasDiscriminator).
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // ToList() → ToListAsync()  (sync I/O throws InvalidOperationException)
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

